mapper.select:
SELECT ptr.*, pf.pen_name as from_pen_name, pt.pen_name as to_pen_name FROM pen_transfer_records ptr LEFT JOIN pens pf ON ptr.from_pen_id = pf.id LEFT JOIN pens pt ON ptr.to_pen_id = pt.id
(ptr.ear_tag LIKE CONCAT('%', #{search}, '%') OR pf.pen_name LIKE CONCAT('%', #{search}, '%') OR pt.pen_name LIKE CONCAT('%', #{search}, '%'))
ORDER BY ptr.event_time DESC LIMIT #{size} OFFSET #{offset}
